import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import "./ConfirmView.css";
import userImg from '../images/user.png';

function ViewCitaConfirmacion() {
    const { idM, fecha, hora } = useParams();
    const [medico, setMedico] = useState(null);
    const [loading, setLoading] = useState(true);
    const navigate = useNavigate();

    useEffect(() => {
        // Obtener datos del médico seleccionado previamente
        const fetchMedico = async () => {
            setLoading(true);
            try {
                const response = await fetch(`/medicos/${idM}`);
                const data = await response.json();
                setMedico(data);
            } catch (error) {
                console.error('Error al obtener el médico:', error);
            }
            setLoading(false);
        };
        if (idM) {
            fetchMedico();
        }
    }, [idM]);

    const handleConfirmar = async (e) => {
        e.preventDefault();
        const response = await fetch(`/api/citas/confirmar`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ idMedico: idM, fecha, hora })
        });
        if (response.ok) {
            navigate("/pacientes/appointment");
        } else {
            alert("Error al confirmar la cita");
        }
    };

    const handleSeleccionarCita = (cita) => {
        // Navega a la vista de confirmación con los datos necesarios
        navigate(`/pacientes/confirmar/${cita.medico.id}/${cita.fecha}/${cita.hora}`);
    };

    if (loading || !medico) return <div>Cargando...</div>;

    return (
        <div className="container-confir-citas">
            <div className="confirmation-card">
                <img src={userImg} alt="Doctor" className="doctor-photo" />
                <div className="doctor-name">
                    <p>{medico.nombre}</p>
                </div>
                <div className="cita-location">
                    <p>{`${fecha} ${hora}`}</p>
                </div>
                <div className="cita-location">
                    <p>{medico.localidad}</p>
                </div>
                <div className="action-buttons">
                    <button className="confirmar-btn" onClick={handleConfirmar}>Confirmar</button>
                    <button className="cancelar-btn" onClick={() => navigate("/usuarios/index/show")}>Cancelar</button>
                </div>
            </div>
        </div>
    );
}

export default ViewCitaConfirmacion;
